import { DependencyList, useEffect } from "react";
import { BlockerFunc, TabEventClient } from "../CachedTabs";
import { useRefFunction } from "../../../hooks";

export type TabBlocker = (next: () => void) => void;

export const useTabBlocker = (blocker: TabBlocker, deps?: DependencyList) => {
    const location = window.location;
    const newBlocker = useRefFunction<BlockerFunc>(() => new Promise<boolean>((resolve) => {
        const next = () => {
            resolve?.(true);
        }

        blocker(next);
    }));

    useEffect(() => {
        const key = TabEventClient.getKeyByPath(location?.pathname) as string;
        TabEventClient.addBlocker(
            key,
            newBlocker
        );

        return () => {
            TabEventClient.removeBlocker(key, newBlocker);
        }
    }, deps ?? [])
}
